func:
// Sla inkomende waarden op in flow context
// zodat alle drie bronnen beschikbaar zijn bij elke berekening
if (msg.topic === 'pv_watt')    flow.set('pv_watt',    Number(msg.payload));
if (msg.topic === 'buffer_top') flow.set('buffer_top', Number(msg.payload));
if (msg.topic === 'buffer_bot') flow.set('buffer_bot', Number(msg.payload));

var pv         = flow.get('pv_watt')    || 0;
var bufferTop  = flow.get('buffer_top') || 0;
var bufferBot  = flow.get('buffer_bot') || 0;

// Wacht tot alle drie waarden bekend zijn
if (pv === 0 && bufferTop === 0 && bufferBot === 0) return null;

var setpoint;
var reden;

// Prioriteit 1: buffer vol → HP hoeft niet te draaien
if (bufferTop >= 68) {
    setpoint = 20;
    reden = 'Buffer vol (top=' + bufferTop + 'C) → setpoint 20C, HP stopt';

// Prioriteit 2: sterk zonne-surplus → maximaal laden
} else if (pv >= 3500) {
    setpoint = 72;
    reden = 'Sterk zonne-surplus (' + pv + 'W) → setpoint 72C';

// Prioriteit 3: matig zonne-surplus → normaal laden
} else if (pv >= 2000) {
    setpoint = 65;
    reden = 'Matig zonne-surplus (' + pv + 'W) → setpoint 65C';

// Prioriteit 4: geen surplus, buffer laag → nachtbijverwarming
} else if (bufferBot < 38) {
    setpoint = 45;
    reden = 'Buffer laag (onder=' + bufferBot + 'C) → setpoint 45C, nachtbijverwarming';

// Prioriteit 5: geen actie nodig
} else {
    setpoint = 20;
    reden = 'Geen surplus, buffer voldoende → setpoint 20C, HP inactief';
}

// Schrijf alleen als setpoint veranderd is (vermijd onnodige Modbus-schrijfacties)
var lastSetpoint = flow.get('last_setpoint') || -1;
if (setpoint === lastSetpoint) return null;

flow.set('last_setpoint', setpoint);

node.log('Setpoint → ' + setpoint + 'C | ' + reden);

msg.payload = {
    value:   [setpoint],
    unitid:  1,
    fc:      6,
    address: 2
};
msg.topic   = 'SETPOINT_' + setpoint + 'C';
msg.reden   = reden;
return msg;

var d = msg.payload;
var written = flow.get('sp_hdr') || false;
var out = '';
if (!written) {
    out = 'timestamp,setpoint_C,pv_watt,buffer_top,buffer_bot,reden\n';
    flow.set('sp_hdr', true);
}
out += [
    new Date().toISOString(),
    d.value[0],
    flow.get('pv_watt')    || 0,
    flow.get('buffer_top') || 0,
    flow.get('buffer_bot') || 0,
    '"' + (msg.reden || '') + '"'
].join(',') + '\n';
msg.payload  = out;
msg.filename = '/home/student/modbus/amh6dc_setpoints.csv';
return msg;

var errorCodes = {
    1:'E0 Waterstroomfout',
    3:'E2 Communicatiefout controller/hydraulisch',
    4:'E3 Uitvoerwatertemperatuursensor T1 defect',
    5:'E4 Tapwatervatsensor T5 defect',
    6:'E5 Condensatorsensor T3 defect',
    7:'E6 Buitenluchttemperatuursensor T4 defect',
    8:'E7 Buffertank boven sensor Tbt1 defect',
    9:'E8 Waterstroomstoring',
    10:'E9 Inzuigtemperatuursensor Th defect',
    11:'EA Uitlaattemperatuursensor Tp defect',
    13:'Ec Buffertank onder sensor Tbt2 defect',
    14:'Ed Waterinlaattemperatuursensor Tw_in defect',
    20:'P0 Lagedrukschakelaarprotectie',
    21:'P1 Hogedrukschakelaarprotectie',
    23:'P3 Compressor overcurrent',
    24:'P4 Hoge uitlaattemperatuur',
    25:'P5 dT water te groot',
    26:'P6 Omvormmodule storing',
    31:'Pb Antibevriezingsbedrijf',
    38:'PP Tw_out-Tw_in afwijkend',
    39:'H0 Hoofdprint communicatiefout',
    41:'H2 Koudemiddel vloeistoftemperatuursensor T2 defect',
    45:'H6 DC-ventilatormotor storing',
    46:'H7 Spanningsprotectie',
    57:'HP Lagedrukprotectie'
};

var code = msg.payload[0];

if (code === 0) {
    // Geen fout — geen actie, geen debug spam
    return null;
}

var omschrijving = errorCodes[code] || 'Onbekende foutcode ' + code;
node.warn('HP FOUT: ' + omschrijving);

msg.payload = {
    timestamp:    new Date().toISOString(),
    foutcode:     code,
    omschrijving: omschrijving
};
msg.topic = 'HP_FOUT';
return msg;

var d = msg.payload;
var written = flow.get('err_hdr') || false;
var out = '';
if (!written) {
    out = 'timestamp,foutcode,omschrijving\n';
    flow.set('err_hdr', true);
}
out += [d.timestamp, d.foutcode, '"' + d.omschrijving + '"'].join(',') + '\n';
msg.payload  = out;
msg.filename = '/home/student/modbus/amh6dc_fouten.csv';
return msg;

var errMsg = '';
if (msg.error && msg.error.message) {
    errMsg = msg.error.message;
} else if (typeof msg.payload === 'string') {
    errMsg = msg.payload;
} else {
    errMsg = JSON.stringify(msg.payload || 'onbekend');
}

var source = msg.topic || 'modbus';
node.error('Modbus fout [' + source + ']: ' + errMsg);

msg.payload      = errMsg;
msg.error_detail = errMsg;
return msg;
